"use client";
import React, { useState } from "react";

export default function LoginRegisterButtons() {
  // Controla qué formulario se muestra: "login", "register" o ""
  const [formType, setFormType] = useState<"login" | "register" | "">("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");

  // Funciones para mostrar cada formulario
  const showLoginForm = () => {
    setMessage("");
    setFormType("login");
  };

  const showRegisterForm = () => {
    setMessage("");
    setFormType("register");
  };

  // Manejo de inicio de sesión
  async function handleLogin() {
    setMessage("Cargando...");
    try {
      const res = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      if (res.ok) {
        setMessage("Inicio de sesión exitoso");
      } else {
        setMessage(data.error || "Error al iniciar sesión");
      }
    } catch (error) {
      setMessage("Error al iniciar sesión");
    }
  }

  // Manejo de registro
  async function handleRegister() {
    setMessage("Cargando...");
    try {
      const res = await fetch("/api/auth/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      if (res.ok) {
        setMessage("Registro exitoso");
      } else {
        setMessage(data.error || "Error al registrar");
      }
    } catch (error) {
      setMessage("Error al registrar");
    }
  }

  return (
    <div className="login-register-container">
      {/* Botones para seleccionar acción (cuando no hay formulario abierto) */}
      {formType === "" && (
        <div>
          <button onClick={showLoginForm}>Iniciar Sesión</button>
          <button onClick={showRegisterForm}>Registrarse</button>
        </div>
      )}

      {/* Formulario de Login o Register */}
      {formType !== "" && (
        <form
          className="login-register-form"
          onSubmit={(e) => {
            e.preventDefault();
            formType === "login" ? handleLogin() : handleRegister();
          }}
        >
          <input
            type="email"
            placeholder="Correo electrónico"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            type="password"
            placeholder="Contraseña"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <div>
            <button type="submit">
              {formType === "login" ? "Iniciar Sesión" : "Registrarse"}
            </button>
            <button type="button" onClick={() => setFormType("")}>
              Cancelar
            </button>
          </div>
        </form>
      )}

      {message && <p className="login-register-message">{message}</p>}
    </div>
  );
}
